
(function(){
  var reduce = window.matchMedia('(prefers-reduced-motion: reduce)').matches;
  var field = document.getElementById('field');
  if(field){
    var SRC={'dailymam':'data:image/png;base64,','tegevajaro':'data:image/png;base64,','yano':'data:image/png;base64,','ogata':'data:image/png;base64,','ropeman':'data:image/png;base64,','sora':'data:image/png;base64,'};
    var pool=['dailymam','tegevajaro','yano','ogata','ropeman','sora'];
    var slots=[{sz:2.6},{sz:2.6},{sz:1.0},{sz:1.0},{sz:1.0},{sz:1.0},{sz:1.0},{sz:0.55},{sz:0.55},{sz:0.55},{sz:0.55}];
    function rnd(a,b){ return a+Math.random()*(b-a); }
    function spot(big){ var x,y; if(big){ x=rnd(5,95); y=(Math.random()<0.5)?rnd(2,17):rnd(81,95); } else { do{ x=rnd(4,96); y=rnd(6,92);}while(x>18&&x<82&&y>20&&y<80); } return [x,y]; }
    slots.forEach(function(sl,idx){ (function(){
      var big=sl.sz>1.4;
      var it=document.createElement('div'); it.className='item';
      var img=document.createElement('img'); img.alt=''; img.src=SRC[pool[idx%pool.length]];
      it.appendChild(img); field.appendChild(it);
      if(reduce){ var q=spot(big); it.style.left=q[0]+'%'; it.style.top=q[1]+'%'; it.style.transform='translate(-50%,-50%) scale('+sl.sz+')'; img.style.opacity='.85'; return; }
      function run(){
        var p=spot(big);
        it.style.left=p[0]+'%'; it.style.top=p[1]+'%';
        it.style.transform='translate(-50%,-50%) scale('+sl.sz+')';
        var dur=3400+Math.random()*3000;
        var a=img.animate([{opacity:0,filter:'blur(8px)',transform:'scale(.85)'},{opacity:0.96,filter:'blur(0px)',transform:'scale(1)',offset:0.5},{opacity:0,filter:'blur(8px)',transform:'scale(.95)'}],{duration:dur,easing:'ease-in-out'});
        a.onfinish=function(){ setTimeout(run, 400+Math.random()*3400); };
      }
      setTimeout(run, Math.random()*5500);
    })(); });
  }

  if(!reduce && 'IntersectionObserver' in window){
    var io=new IntersectionObserver(function(es){
      es.forEach(function(e){ if(e.isIntersecting){ e.target.classList.add('in'); io.unobserve(e.target); } });
    },{threshold:.16,rootMargin:'0px 0px -8% 0px'});
    document.querySelectorAll('.reveal').forEach(function(n){ io.observe(n); });
  }

  document.querySelectorAll('.card').forEach(function(card){
    card.addEventListener('click', function(ev){
      var href=card.getAttribute('href');
      if(reduce||!href||href==='#') return;
      ev.preventDefault();
      var c=getComputedStyle(card).getPropertyValue('--c').trim();
      var m=document.createElement('div'); m.className='mask'; m.style.background=c;
      document.body.appendChild(m);
      m.animate([{transform:'translateY(100%)'},{transform:'translateY(0)'}],{duration:420,easing:'cubic-bezier(.7,0,.2,1)',fill:'forwards'})
        .onfinish=function(){ window.location.href=href; };
    });
  });

  /* 戻る(bfcache復元)で、覆ったままの遷移マスクが残るのを防ぐ */
  window.addEventListener('pageshow', function(){
    document.querySelectorAll('.mask').forEach(function(m){ m.remove(); });
  });
})();
